pragma solidity ^0.8.0;

import "./FolksSmartContractLibrary.sol";

contract FolksSmartContractLibraryTest {
    FolksSmartContractLibrary public token;

    constructor(uint256 initialSupply) {
        token = new FolksSmartContractLibrary(initialSupply);
    }

    function testTransfer() public {
        uint256 initialBalance = token.balanceOf(address(this));
        uint256 transferAmount = 100;

        bool success = token.transfer(address(this), transferAmount);
        require(success, "Transfer failed");
        require(token.balanceOf(address(this)) == initialBalance + transferAmount, "Balance not updated correctly");
    }

    function testApprove() public {
        address spender = address(0x123);
        uint256 approveAmount = 100;

        bool success = token.approve(spender, approveAmount);
        require(success, "Approve failed");
        require(token.allowance(address(this), spender) == approveAmount, "Allowance not updated correctly");
    }

    function testTransferFrom() public {
        address spender = address(0x123);
        uint256 approveAmount = 100;
        uint256 transferAmount = 50;

        token.approve(spender, approveAmount);
        bool success = token.transferFrom(address(this), spender, transferAmount);
        require(success, "TransferFrom failed");
        require(token.balanceOf(spender) == transferAmount, "Recipient balance not updated correctly");
        require(token.allowance(address(this), spender) == approveAmount - transferAmount, "Allowance not updated correctly");
    }
}
