pragma solidity ^0.8.0;

import "./FolksSmartContractLibrary.sol";

contract FolksSmartContractLibraryErrorHandling {
    FolksSmartContractLibrary public token;

    constructor(uint256 initialSupply) {
        token = new FolksSmartContractLibrary(initialSupply);
    }

    function testTransferErrorHandling() public {
        try token.transfer(address(0), 100) {
            revert("Transfer to zero address should fail");
        } catch Error(string memory reason) {
            require(keccak256(abi.encodePacked(reason)) == keccak256("Transfer to the zero address"), "Incorrect error message");
        } catch (bytes memory) {
            revert("Unexpected error type");
        }
    }

    function testApproveErrorHandling() public {
        try token.approve(address(0), 100) {
            revert("Approve to zero address should fail");
        } catch Error(string memory reason) {
            require(keccak256(abi.encodePacked(reason)) == keccak256("Approve to the zero address"), "Incorrect error message");
        } catch (bytes memory) {
            revert("Unexpected error type");
        }
    }

    function testTransferFromErrorHandling() public {
        try token.transferFrom(address(0), address(this), 100) {
            revert("TransferFrom from zero address should fail");
        } catch Error(string memory reason) {
            require(keccak256(abi.encodePacked(reason)) == keccak256("Transfer from the zero address"), "Incorrect error message");
        } catch (bytes memory) {
            revert("Unexpected error type");
        }
    }
}
